/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Solution {
public:
    int rob(TreeNode* root) {
        auto res = robHelper(root);
        return max(res.first, res.second);
    }

private:
    pair<int, int> robHelper(TreeNode* root) {
        if (!root) {
            return {0, 0};
        }
        auto left = robHelper(root->left);
        auto right = robHelper(root->right);
        return {root->val + left.second + right.second,
                max(left.first, left.second) + max(right.first, right.second)};
    }
};

# Time:  O(n)
# Space: O(h)

class Solution(object):
    def rob(self, root):
        """
        :type root: TreeNode
        :rtype: int
        """
        def robHelper(root):
            if not root:
                return (0, 0)
            left, right = robHelper(root.left), robHelper(root.right)
            return (root.val + left[1] + right[1], max(left) + max(right))

        return max(robHelper(root))
